<template>
    <div>
        <!-- <NavBar/> -->
        <div v-show="false">
            <!--Circle Form-->
            <!--Pin Form-->
            <form class="formcontainer" id="pinForm" @submit.prevent="submitPin(formData)">
                <div class="form-group">
                    <!-- <label for="title">Title</label> -->
                    <input v-model="formData['title']" type="text" class="form-control" id="title" placeholder="Title" required>
                </div>
                <div class="form-group">
                    <!-- <label for="desc">Description</label> -->
                    <textarea v-model="formData['desc']" class="form-control" id="desc" rows="1" placeholder="Description" required></textarea>
                </div>
                <div class="form-group">
                    <label for="category">Category</label>
                    <select v-model="formData['category']" class="form-control" id="category">
                        <option v-for="i in categories" :key="i" :selected="i == 'default'">
                            x`
                        </option>
                    </select>
                </div>
                <div class="form-group">
                    <label for="image">Image</label>
                    <img :src="file" class="imgpreview"/>
                    <input v-on:change="onFileChange($event)" type="file" class="form-control-file" id="image">
                </div>
                <!-- <button @click.prevent="submitPin(formData)" type="submit" class="btn btn-primary">Submit</button> -->
                <div v-html="captcha['data']"></div><br>
                <input v-model="formData['captcha']" class="form-control" id="captcha" required/><br>
                <button type="submit" class="btn btn-primary">Submit</button>
                <div class="text-danger" v-if="wrongform"><br>{{wrongform_msg}}</div>
            </form>
            <!--Item creation buttons, pin, circle polygon-->
            <div id="itembuttons" class="w3-center">
                <p>Create a pin, circle or polygon</p>
                <button @click="setForm('pin')" class="w3-border" id="pinbutton"><img src="@/assets/icons/default.png" alt="pin"/></button>&nbsp;
                <button @click="setForm('circle')" class="w3-border" id="circlebutton"><img src="@/assets/icons/circle.png" alt="circle"/></button>&nbsp;
                <button @click="setForm('poly')" class="w3-border" id="polybutton"><img src='@/assets/icons/polygon.png' alt="polygon"/></button>
                <br><br><i v-if="clickLocation"><b>Lat</b>: {{clickLocation.lat}}<br><b>Lng</b>: {{clickLocation.lng}}</i>
            </div>
        </div>
        <div id="mapid">
        </div>
    </div>
</template>

<script>
// import L, { LatLng } from 'leaflet'
import L from 'leaflet'
import axios from 'axios'

export default {
    created () {
    },
    data () {
        return {
            apiurl: process.env.VUE_APP_APIURL,
            clickLocation: null,
            file: null,
            //categories should be retieved from icons
            categories: [
                "default",
                "bike",
                "bird",
                "fire",
                "nature",
                "secret",
                "warning",
                "park",
                "food",
                "books",
                "music",
                "animals",
                "wateranimals",
                "entertainment",
            ],
            icons: {},
            formData: {},
            wrongform: false,
            wrongform_msg: "",
            pinForm: null,
            circleForm: null,
            polyForm: null,
            popup: null,
            popupContent: null,
            pins: [],
            submitted: false,
            location: null,
            map: null,
            tile: null,
            captcha: {
                text: null,
                data: null,
            }
        };
    },
    components: {
    },
    props: [],
    mounted() {
        this.pinForm = document.getElementById("pinForm")
        this.circleForm = document.getElementById("circleForm")
        this.polyForm = document.getElementById("polyForm")

        this.popupContent = document.getElementById('itembuttons')
        let heightStyle = `height: ${window.innerHeight}px;width: ${window.innerWidth}px;`
        document.getElementById("mapid").style = heightStyle
        this.map = L.map('mapid').setView([19.352610894378625, -99.1845703125], 6)
        this.setMap()
        this.tile = L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: 'The Universe'
        }).addTo(this.map)
        // console.log(this.tile);

        //set popup
        this.popup = L.popup()
        this.map.on("click", this.onMapClick)

        //create icons
        this.categories.forEach(e => {
            let icon_url = require("@/assets/icons/" + e + ".png");
            this.icons[e] = L.icon({
                iconUrl: icon_url,
                iconSize: [60, 60],
                iconAnchor: [30, 60]
            })
        });

        //poblate map with pins and get all pins
        axios.get(this.apiurl + "/map/pins")
            .then(res => {
                this.pins = res.data;
                // console.log(this.pins);
                this.pins.forEach(element => {
                    //console.log(element);
                    L.marker([element.lat, element.lng], {icon: this.icons[element.category]}).addTo(this.map).bindPopup(
                    `
                        <div align="center">
                            <h1>${element.title || ""}</h1>
                            <img width="100%" src='${element.img || ""}'/><br>
                            <p style='font-size:1.5em'>${element.desc}</p>
                            Latitude :   <i>${element.lat}</i><br>
                            Longitude:   <i>${element.lng}</i><br>
                            Category: <b><i>${element.category}</i></b>
                        </div>
                    `);
                });
            }).catch(err => {
                console.log(err);
            });
    },
    methods: {
        decrypt(text){
            let s = process.env.VUE_APP_SECRET;
            let a = [];
            for(let i of text){
                for(let j of s){
                    i = i ^ j.charCodeAt(0);
                }
                a.push(String.fromCharCode(i));
            }
            return a.join('');
        },
        getCaptcha(){
            axios.get(this.apiurl + "/captcha")
                .then(res => {
                    this.captcha['text'] = this.decrypt(res.data.text);
                    this.captcha['data'] = res.data.data;
                }).catch(err => {
                    console.log(err);
                });
        },
        resizeImage(base64Str, maxWidth = 200, maxHeight = 300) {
            return new Promise((resolve) => {
                let img = new Image();
                img.src = base64Str;
                img.onload = () => {
                    let canvas = document.createElement('canvas');
                    const MAX_WIDTH = maxWidth;
                    const MAX_HEIGHT = maxHeight;
                    let width = img.width;
                    let height = img.height;

                    if (width > height) {
                        if (width > MAX_WIDTH) {
                            height *= MAX_WIDTH / width;
                            width = MAX_WIDTH;
                        }
                    } else {
                        if (height > MAX_HEIGHT) {
                            width *= MAX_HEIGHT / height;
                            height = MAX_HEIGHT;
                        }
                    }
                    canvas.width = width;
                    canvas.height = height;
                    let ctx = canvas.getContext('2d');
                    ctx.drawImage(img, 0, 0, width, height);
                    resolve(canvas.toDataURL());
                }
            })
        },
        getBase64(file) {
            let promise = new Promise((resolve, reject) => {
                const reader = new FileReader();
                reader.readAsDataURL(file);
                reader.onload = () => resolve(reader.result);
                reader.onerror = error => reject(error);
            });
            promise.then(values => {
                this.resizeImage(values).then(v => {
                    this.file = v
                })
                //this.file = values
            })
        },
        onFileChange(e){
            this.getBase64(e.target.files[0])
        },
        submitPin(data){
            data['img'] = this.file
            // console.log(this.clickLocation)
            //validate form
            data['category'] = data['category'] ? data['category'] : "default";
            data['lat'] = this.clickLocation.lat;
            data['lng'] = this.clickLocation.lng;
            if(data['captcha'] == this.captcha.text){
                if(data['lat'] >= -90 && data['lat'] <= 90 && data['lng'] >= -180 && data['lng'] <= 180){
                    this.map.closePopup()
                    //show data in map
                    L.marker(this.clickLocation, {icon: this.icons[data['category']]}).addTo(this.map).bindPopup(
                    `
                        <div align="center">
                            <h1>${data['title'] || ""}</h1>
                            <img width="100%" src="${data['img'] || ""}"/><br>
                            <p style='font-size:1.5em'>${data['desc'] || ""}</p>
                            Latitude :   <i>${data['lat']}</i><br>
                            Longitude:   <i>${data['lng']}</i><br>
                            Category: <b><i>${data['category']}</i></b>
                        </div>
                    `);
                    //post data
                    axios.post(this.apiurl + "/map/pins", data)
                        .then(() => {
                            Object.keys(this.formData).forEach((i) => this.formData[i] = null);
                            this.file = null;
                        }).catch(err => {
                            console.log(err);
                        });
                }else{
                    this.wrongform = true;
                    this.wrongform_msg = "Wrong data entered, try another location!";
                    this.formData['captcha'] = "";
                    this.getCaptcha();
                }
            }else{
                this.wrongform = true;
                this.wrongform_msg = "Wrong Captcha, Try again!";
                this.formData['captcha'] = "";
                this.getCaptcha();
            }
        },
        setForm(ty){            
            switch(ty){
                case "pin":
                    this.popup.setContent(this.pinForm)
                break
                case "circle":
                    alert("Sorry m8, not available at the time")
                    // this.popup.setContent(this.circleForm)
                break
                case "poly":
                    alert("Sorry m8, not available at the time");
                    // this.popup.setContent(this.polyForm)
                break;
            }
        },
        onMapClick(e){
            this.getCaptcha();
            this.clickLocation = e.latlng;
            this.wrongform = false;
            //check how to center map at click
            // this.map.setView(...);
            this.popup
                .setLatLng(e.latlng)
                //.setContent(this.popupContent + e.latlng.toString())
                .setContent(this.popupContent)
                .openOn(this.map)
        },
        setMap(){
            if(!("geolocation" in navigator)) {
                console.log('Geolocation is not available.')
            }
            // get position
            navigator.geolocation.getCurrentPosition(pos => {
                this.location = pos
                this.map.setView(new L.LatLng(this.location.coords.latitude, this.location.coords.longitude), 8)
                L.marker([this.location.coords.latitude, this.location.coords.longitude]).addTo(this.map).bindPopup(
                    `<div align="center">
                        <h1>You are Here</h1>
                        <p style='font-size:1.5em'>Whatcha doing?</p>
                        Latitude :   <i>${this.location.coords.latitude}</i><br>
                        Longitude:   <i>${this.location.coords.longitude}</i><br>
                    </div>`
                );
                //console.log(this.location)
            }, err => {
                this.errorStr = err.message
                console.log("error getting location, msg: " + this.errorStr)
            })
        }
    }
}
</script>

<style scoped>
#mapid {
    left:0;
    top:0;
    position:absolute;
    /*width:100%;
    height: 100%;*/
}
#itembuttons{
    width:100%;
}
.imgpreview{
    width:8em;
}
.icon {
    width:4em;
    height:4em;
}
</style>
