<script>
import Header from '@/components/Header';
import Loading from '@/components/Loading';
import axios from 'axios';
export default {
    data(){
        return {
            apiurl: process.env.VUE_APP_APIURL,
            projects: [],
            captcha: {
                text: null,
                data: null,
            },
            wrongform: null,
            wrongform_msg: null,
            links: [
                {
                    icon: require('@/assets/media/github.png'),
                    url: 'https://github.com/k3ll3x',
                    name: "Github",
                },
                {
                    icon: require('@/assets/media/soundcloud.png'),
                    url: 'https://soundcloud.com/user-99991795/',
                    name: "Soundcloud: Nuvhandra",
                },
                {
                    icon: require('@/assets/media/soundcloud.png'),
                    url: 'https://soundcloud.com/kellex_urps',
                    name: "Soundcloud: Fred Kelder",
                },
                {
                    icon: require('@/assets/media/youtube.png'),
                    url: 'https://www.youtube.com/channel/UCoNfVL3YH5pNd3NqRDI2rIw',
                    name: "YouTube Channel",
                },
                {
                    icon: require('@/assets/media/twitch.png'),
                    url: 'https://www.twitch.tv/nuvhandra',
                    name: "Twitch Channel",
                },
                {
                    icon: require('@/assets/media/discord.png'),
                    url: 'https://discord.gg/sKUTZUDQ',
                    name: "Discord Channel",
 
                }
            ],
            formsuccess: false,
            form: {
                name: null,
                email: null,
                subject: null,
                comment: null
            }
        }
    },
    methods:{
        submitForm(){
            //console.log(this.form);
            if(this.form.captcha == this.captcha.text){
                axios.post(this.apiurl + "/contact", this.form)
                    .then(() => {
                        console.log("success");
                        this.formsuccess = true;
                        this.wrongform = false;
                        this.wrongform_msg = null;
                        // Object.keys(this.form).forEach((i) => this.form[i] = null);
                    }).catch(err => {
                        console.log(err);
                        this.formsuccess = false;
                    });
            }else{
                this.wrongform = true;
                this.wrongform_msg = "Wrong Captcha, Try again!";
                this.form['captcha'] = "";
                this.formsuccess = false;
                this.getCaptcha();
            }
        },
        decrypt(text){
            let s = process.env.VUE_APP_SECRET;
            let a = [];
            for(let i of text){
                for(let j of s){
                    i = i ^ j.charCodeAt(0);
                }
                a.push(String.fromCharCode(i));
            }
            return a.join('');
        },
        getCaptcha(){
            axios.get(this.apiurl + "/captcha")
                .then(res => {
                    this.captcha['text'] = this.decrypt(res.data.text);
                    this.captcha['data'] = res.data.data;
                }).catch(err => {
                    console.log(err);
                });
        },
    },
    mounted(){
        this.getCaptcha();
        axios.get(this.apiurl + "/projects/rnd/16")
            .then(res => {
                for(let i in res.data){
                    let item = {
                        title: res.data[i].title,
                        desc: res.data[i].content[0],
                        img: res.data[i].img[0],
                        url: res.data[i].url
                    };
                    // console.log(item);
                    // console.log(this.projects);
                    this.projects.push(item);
                }
                //console.log(res.data);
            }).catch(err => {
                console.log(err);
            });
    },
    components: {
        Loading,
        Header
    }
}
</script>

