import Vue from 'vue'
import VueRouter from 'vue-router'
import Homepage from '../home/Homepage.vue'
import Donate from '../home/Donate.vue'
import Mapa from '../map/Map.vue'
import AddProject from '../projects/AddProject.vue'
import Project from '../projects/Project.vue'
import Projects from '../projects/Projects.vue'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Homepage
  },
  {
    path: '/map',
    name: 'Map',
    component: Mapa
  },
  {
    path: '/donate',
    name: 'Donate',
    component: Donate
  },
  {
    path: '/project/:url',
    name: 'Project',
    component: Project
  },
  {
    path: '/projects',
    name: 'Projects',
    component: Projects
  },
]

const router = new VueRouter({
  mode: 'history',
  routes
})

router.beforeEach((to, from, next) => {
  // console.log(to);
  // console.log(from);
  if(to.path.includes("www") || to.path.includes("http")){
    let nurl = to.path.split('/');
    nurl.reverse();
    nurl.pop();
    nurl.reverse();
    if(to.path.includes("www")){
      nurl = "http:" + "//" + nurl[nurl.length - 1]
    }else{
      nurl = nurl[0] + "//" + nurl[nurl.length - 1]
    }
    window.open(nurl,"_blank")
  }else{
    return next();
  }
  return next(false);
})

export default router

if(process.env.NODE_ENV === 'development'){
  router.addRoute(
    {
      path: '/addproject',
      name: 'AddProject',
      component: AddProject
    },
  );
}