<template>
    <div>
        <br><br><br>
        <div class="container w3-brown w3-round-large w3-panel w3-border">
            <br>
            <h1 class="w3-dark-gray w3-text-white w3-round-xlarge w3-center">{{project.title}}</h1>
            <hr>
            <Loading v-if="Object.keys(project).length == 0"/>
            <div v-for="(c, i) in project.content" :key="i" class="w3-row">
                <div class="w3-container">
                    <div class="w3-third w3-khaki w3-round-xlarge w3-center" v-if="project.img[i]">
                        <br>
                        <img class="image" :src="project.img[i]"/>
                        <br><br>
                    </div>
                    <div class="w3-light-gray w3-round-xlarge w3-padding w3-right w3-left" v-html="c" :style="project.img[i] ? 'width:60%' : 'width:100%'">
                    </div>
                </div>
                <hr>
            </div>
            <br>
        </div>
    </div>
</template>

<script>
import axios from 'axios'
import Loading from '@/components/Loading'

export default {
    components:{
        Loading
    },
    data(){
        return {
            apiURL: process.env.VUE_APP_APIURL,
            url: this.$route.params.url,
            project: {},
        }
    },
    created(){
        this.getProjectByUrl();
    },
    methods:{
        getProjectByUrl(){
            axios.get(this.apiURL + "/projects/url/" + this.url)
                .then(res => {
                    this.project = res.data[0];
                })
                .catch(err => console.log(err))
        }
    }
}
</script>

<style scoped>
.image {
    width:75%;
    border: 5px solid #555;
}
</style>