<template>
    <div class="container w3-center w3-round-large w3-sand ">
        <br><br><br><br><br><br>
        <form>
            <div class="container w3-lime w3-round-large w3-panel w3-border">
                <h1><input @change="searchProject" placeholder="Search project" v-model="project_search"/></h1>
                <label for="category">Category</label><br>
                <select @change="searchProject" v-model="category" id="category" class="form-group">
                    <option v-for="i in categories" :key="i">
                        {{i}}
                    </option>
                </select>
            </div>
            <div v-if="searched_projects.length != 0" class="container w3-lime w3-round-large w3-panel w3-border">
                <div class="w3-row-padding">
                    <div class="w3-col l3 m6 w3-margin-bottom" v-for="(p, i) in searched_projects" :key="i">
                        <a @click="loadProject(p)">
                            <div class="w3-display-container">
                                <div class="w3-card">
                                    <header class="w3-green w3-center">
                                        <h3>{{p.title}}</h3>
                                    </header>
                                    <div class="w3-container">
                                        <img class="w3-center" :src="p.img[0]" style="width:100%"><br><br>
                                        <p class="w3-khaki w3-padding">{{p.content[0]}}</p>
                                    </div>
                                </div>
                            </div>
                        </a>
                    </div>
                </div>
            </div>
            <div class="container w3-lime w3-round-large w3-panel w3-border">
                <br>
                <button @click.prevent="cleanData" class="btn w3-sand">Clear Data</button>
                <div v-if="projectLoaded">
                    &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                    <div v-html="captcha['data']"></div>
                    <input v-model="captcha['input']" id="captcha" required/>
                    <button @click.prevent="deleteProject" class="btn w3-red">Delete Project</button>
                </div>
                <br><br>
            </div>
            <div class="w3-row">
                <div class="w3-container w3-half">
                    <div class="container w3-lime w3-round-large w3-panel w3-border">
                        <div class="form-group">
                            <label>Title</label>
                            <input class="form-control" v-model="title"/>
                        </div>
                    </div>
                    <div class="container w3-lime w3-round-large w3-panel w3-border">
                        <div class="form-group">
                            <label>URL</label>
                            <input placeholder="outside url include 'http' or 'www'" class="form-control" v-model="url"/>
                        </div>
                    </div>
                    <div class="container w3-lime w3-round-large w3-panel w3-border">
                        <div class="form-group">
                            <label>Categories</label>
                            <input placeholder="separated by commas ," class="form-control" v-model="pcategories"/>
                        </div>
                    </div>
                    <div class="container w3-lime w3-round-large w3-panel w3-border" v-for="(box, counter) in boxes" :key="counter">
                        <button @click.prevent="deleteBox(counter)" class="btn left w3-red" v-if="counter != 0">X</button>
                        <div class="form-group">
                            <label for="image">Image</label><br>
                            <div class="container w3-border" v-if="file[counter]">
                                <button @click.prevent="deleteFile(counter)" class="btn w3-red">X</button>
                                <img :src="file[counter]" class="imgpreview-small"/>
                            </div>
                            <br>
                            <input v-on:change="onFileChange($event, counter)" type="file" class="form-control-file w3-sand w3-round" id="image">
                            <br>
                            <label :for="box + counter">html content</label>
                            <textarea class="form-control" :id="box + counter" v-model="box.html" rows="3"></textarea>
                        </div>
                        <hr/>
                    </div>
                    <div class="container w3-light-green w3-round-large">
                        <br>
                        <button @click.prevent="addBox()" class="btn align-text-top">Add Box</button>
                        <br><br>
                    </div>
                </div>                
                <hr>
                <div class="w3-container w3-half">
                    <h3 style="color:lightgray">Preview</h3>
                    <h2>{{title}}</h2>
                    <hr>
                    <div class="container w3-white w3-justify" id="renderedbox">
                        <div class="container" v-for="(box, counter) in boxes" :key="counter">
                            <img :src="file[counter] || 0" class="imgpreview w3-center" v-if="file[counter]"/>
                            <div v-html="box.html"></div>
                            <hr>
                        </div>
                    </div>
                    <br>
                    <button @click.prevent="saveBox()" class="btn w3-black"><b>Send</b></button>
                    <br><br><br>
                </div>
            </div>
        </form><br><br>
    </div>
</template>

<script>
import axios from 'axios'
export default {
    components:{
    },
    data(){
        return{
            apiURL: process.env.VUE_APP_APIURL,
            searched_projects: [],
            project_search: null,

            id: null,
            title: "",
            url: "",
            file: [],
            counter: 0,
            boxes: [
                {
                    "html": "",
                }
            ],
            pcategories: "",

            categories: null,
            category: null,
            projectLoaded: false,
            captcha: {
                text: null,
                data: null,
                input: null,
            },
        }
    },
    created() {
        this.loadCategories();
    },
    methods: {
        decrypt(text){
            let s = process.env.VUE_APP_SECRET;
            let a = [];
            for(let i of text){
                for(let j of s){
                    i = i ^ j.charCodeAt(0);
                }
                a.push(String.fromCharCode(i));
            }
            return a.join('');
        },
        getCaptcha(){
            axios.get(this.apiURL + "/captcha")
                .then(res => {
                    this.captcha['text'] = this.decrypt(res.data.text);
                    this.captcha['data'] = res.data.data;
                }).catch(err => {
                    console.log(err);
                });
        },
        loadCategories(){
            axios.get(
                this.apiURL + "/projects_categories"
            )
            .then(res => {
                this.categories = res.data;
                this.categories.push("any");
            })
            .catch(err => {
                console.log(err)
            })
        },
        deleteProject(){
            if(this.captcha.text == this.captcha.input){
                let headers = {
                    'add-project-pass': "r538489234tfd9fr239ruyw09efy09234r02f",
                };
                axios.post(
                    this.apiURL + "/deleteproject",
                    { id: this.id },
                    {
                        headers: headers
                    }
                )
                .then(res => {
                    console.log(res);
                    this.cleanData();
                })
                .catch(err => {
                    console.log(err)
                })
            }                
            this.getCaptcha();
            this.captcha.input = null;
        },
        loadProject(project){
            this.cleanData();
            this.getCaptcha();
            this.projectLoaded = true;

            this.id = project._id;
            this.title = project.title;
            if(project.url.includes("http") || project.url.includes("www")){
                this.url = project.url;
            }else{
                this.url = project.url.split('/');
                this.url = this.url[this.url.length - 1];
            }
            this.file = project.img;
            this.file.push("");
            this.file.splice(this.file.length - 1, 1);
            this.boxes = [];
            project.content.forEach(e => {
                this.boxes.push(
                    {
                        "html": e
                    }
                );
            });
            this.pcategories = "";
            project.categories.forEach(e => {
                this.pcategories += e + ',';
            });
        },
        searchProject(){
            //search by category name
            let url = this.apiURL;
            url += (this.category == "any" || this.category == null) ? "/projects" : "/projects/category/" + this.category;
            axios.get(
                url
            )
            .then(res => {
                if(this.project_search){
                    this.searched_projects = [];
                    res.data.forEach(element => {
                        if(element.title.toLowerCase().includes(this.project_search.toLowerCase()) || element.content[0].toLowerCase().includes(this.project_search.toLowerCase())){
                            this.searched_projects.push(element);
                        }
                    });
                }else{
                    this.searched_projects = res.data;
                }
            })
            .catch(err => {
                console.log(err)
            })
        },
        resizeImage(base64Str, maxWidth = 200, maxHeight = 300) {
            return new Promise((resolve) => {
                let img = new Image();
                img.src = base64Str;
                img.onload = () => {
                    let canvas = document.createElement('canvas');
                    const MAX_WIDTH = maxWidth;
                    const MAX_HEIGHT = maxHeight;
                    let width = img.width;
                    let height = img.height;

                    if (width > height) {
                        if (width > MAX_WIDTH) {
                            height *= MAX_WIDTH / width;
                            width = MAX_WIDTH;
                        }
                    } else {
                        if (height > MAX_HEIGHT) {
                            width *= MAX_HEIGHT / height;
                            height = MAX_HEIGHT;
                        }
                    }
                    canvas.width = width;
                    canvas.height = height;
                    let ctx = canvas.getContext('2d');
                    ctx.drawImage(img, 0, 0, width, height);
                    resolve(canvas.toDataURL());
                }
            })
        },
        getBase64(file) {
            let promise = new Promise((resolve, reject) => {
                const reader = new FileReader()
                reader.readAsDataURL(file)
                reader.onload = () => resolve(reader.result)
                reader.onerror = error => reject(error)
            });
            promise.then(values => {
                this.resizeImage(values).then(v => {
                    //this.file.push(v)
                    this.file.splice(this.counter,1,v);
                })
                //this.file.push(values)
            })
        },
        onFileChange(e, c){
            this.counter = c;
            this.getBase64(e.target.files[0]);
        },
        addBox(){
            this.boxes.push(
                {
                    "html": "",
                }
            );
        },
        deleteBox(counter) {
            this.boxes.splice(counter,1)
            this.file.splice(counter,1)
        },
        deleteFile(counter){
            this.file.splice(counter,1,"")
        },
        cleanData(){
            this.searched_projects = [];
            this.project_search = null;
            this.id = null;
            this.title = "";
            this.url = "";
            this.file = [];
            this.boxes = [
                {
                    "html": "",
                }
            ];
            this.category = null;
            this.pcategories = "";
            this.loadCategories();
            this.projectLoaded = false;
        },
        saveBox(){
            let content = [];
            this.boxes.forEach(e => content.push(e.html));
            let cat = [];
            this.pcategories.split(',').forEach(e => {
                if(e != ""){
                    cat.push(e);
                }
            });
            let _project = {
                _id: this.id,
                title: this.title,
                url: this.url,
                img: this.file,
                content: content,
                categories: cat
            };
            let headers = {
                'add-project-pass': "r538489234tfd9fr239ruyw09efy09234r02f",
            };
            axios.post(
                this.apiURL + "/projects",
                _project,
                {
                    headers: headers
                }
            )
            .then(res => {
                console.log(res);
                this.cleanData();
            })
            .catch(err => {
                console.log(err)
            })
        }
    }
}
</script>

<style scoped>
    .imgpreview {
        text-align:center;
        width: 100%;
    }
    .imgpreview-small {
        width: 20%;
    }
    .left {
        position: absolute;
        left: 4em;
    }
    .right {
        position: absolute;
        right: 4em;
    }
    div {
        word-wrap: break-word;
    }
